#include <bits/stdc++.h>
using namespace std;
const int N=2e5+5;
struct Edge{
	int to,val;
};
int t,n,fa[N];
long long f[N][2],u[N],ans,df[N];
bool b[N];
vector<Edge> g[N];
void dfs1(int x){
	f[x][0]=0,b[x]=1;
	int len=g[x].size();
	bool flag=true;
	for(int i=0;i<len;i++)
		if(!b[g[x][i].to]){
			flag=false;
			dfs1(g[x][i].to);
			f[x][0]+=min(1LL*g[x][i].val,f[g[x][i].to][0]);
		}else
			fa[x]=g[x][i].to,df[x]=g[x][i].val;
	if(flag)
		f[x][0]=1e18;
}
void dfs2(int x){
	f[x][1]=f[x][0],b[x]=1;
	if(f[x][1]==1e18)
		f[x][1]=0;
	if(x!=1){
		if(g[fa[x]].size()-(fa[x]!=1)>1)
			u[x]=min(df[x],u[fa[x]]%((int)1e18)+f[fa[x]][0]-min(df[x],f[x][0]));
		else
			u[x]=min(df[x],u[fa[x]]);
		f[x][1]+=u[x];
	}else
	    u[x]=1e18;
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(!b[g[x][i].to])
			dfs2(g[x][i].to);
	ans=max(ans,f[x][1]);
}
int main(){
	scanf("%d",&t);
	while(t--){
		scanf("%d",&n);
		for(int i=1;i<=n;i++)
			g[i].clear(),b[i]=0;
		for(int i=1;i<n;i++){
			int a,b,c;
			scanf("%d%d%d",&a,&b,&c);
			g[a].push_back({b,c});
			g[b].push_back({a,c});
		}
		ans=0;
		dfs1(1);
		for(int i=1;i<=n;i++)
			b[i]=0;
		dfs2(1);
		printf("%lld\n",ans);
	}
	return 0;
}
